function normalizeColorLabel(label) {
  if (!label) return "";
  return label
    .replace(/\bproduct\b/gi, "")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (char) => char.toUpperCase());
}

function normalizeColorId(label, fallbackId) {
  const normalized = normalizeColorLabel(label)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
  return normalized || fallbackId;
}

function normalizeProductOptions(product) {
  const colorOption = product.extraOptions?.color;
  if (!colorOption) return product;

  const values = (colorOption.values || []).map((value, index) => {
    const cleanLabel = normalizeColorLabel(value.label || value.id || "Color");
    return {
      ...value,
      id: normalizeColorId(cleanLabel, `color-${index + 1}`),
      label: cleanLabel,
      images: value.images?.length ? value.images : product.images
    };
  });

  return {
    ...product,
    extraOptions: {
      ...product.extraOptions,
      color: {
        ...colorOption,
        label: "Color",
        values
      }
    }
  };
}

const catalogProducts = catalogProductsRaw.map((product) =>
  normalizeProductOptions({
    ...product,
    id: `catalog-${product.id}`
  })
);

